sql:
SELECT username
FROM users
WHERE user_id IN (SELECT user_id FROM submissions);

SELECT AVG(average_rating) AS average_submission_rating
FROM user_contest_stats
WHERE contest_id = 0;

external_knowledge:
; In this context, 'winners' refers to the contestants who achieved the first position in a contest, as determined by the 'winner_position' column in the 'contest_results' table; 
; The 'average submission rating' is a measure of the overall quality of submissions in a contest, calculated from the ratings given by users; 
; The 'average rating of the winner' refers to the average rating achieved by the winner in the specific contest.

sql:
SELECT user_id, submissions_count
FROM user_contest_stats
WHERE contest_id = 0;

SELECT DISTINCT T1.name
FROM users AS T1
JOIN submissions AS T2 ON T1.user_id = T2.user_id;

SELECT average_rating
FROM user_contest_stats
WHERE user_id = 0 AND contest_id = 0;

SELECT contest_id, submissions_count
FROM user_contest_stats
ORDER BY submissions_count DESC;

SELECT contest_id, AVG(average_rating) AS avg_submission_rating
FROM user_contest_stats
GROUP BY contest_id;

SELECT user_id, contest_id, AVG(submissions_count) AS avg_submissions
FROM user_contest_stats
GROUP BY user_id, contest_id;
